7	/// <summary>
8	///     Parallelizable tests for <see cref="SpinnerView"/> render behavior.
9	/// </summary>
10	public class SpinnerViewTests : TestDriverBase
11	{
12	    [Fact]
13	    public void AdvanceAnimation_DefaultDelay_ThrottlesRapidCalls ()
14	    {
15	        // SpinnerStyle.Line default delay is 130 ms; calling immediately does not advance the frame.
16	        IDriver driver = CreateTestDriver (5, 1);
17	        driver.Clip = new Region (driver.Screen);
18	
19	        SpinnerView view = new ()
20	        {
21	            Driver = driver,
22	            X = 0,
23	            Y = 0
24	        };
25	        view.BeginInit ();
26	        view.EndInit ();
27	        view.LayoutSubViews ();
28	
29	        view.Draw ();
30	        string frame1 = driver.Contents! [0, 0].Grapheme;
31	
32	        // Called immediately — not enough time has elapsed (130 ms throttle).
33	        view.AdvanceAnimation ();
34	        view.Draw ();
35	        string frame2 = driver.Contents [0, 0].Grapheme;
36	
37	        Assert.Equal (frame1, frame2);
38	    }
39	
40	    [Fact]
