14	    [Fact]
15	    public void AddTimeout_Callback_Can_Add_New_Timeout ()
16	    {
17	        using IApplication app = Application.Create ();
18	        app.Init (DriverRegistry.Names.ANSI);
19	
20	        var firstFired = false;
21	        var secondFired = false;
22	
23	        app.AddTimeout (TimeSpan.FromMilliseconds (50),
24	                        () =>
25	                        {
26	                            firstFired = true;
27	
28	                            // Add another timeout from within callback
29	                            app.AddTimeout (TimeSpan.FromMilliseconds (50),
30	                                            () =>
31	                                            {
32	                                                secondFired = true;
33	                                                app.RequestStop ();
34	
35	                                                return false;
36	                                            });
37	
38	                            return false;
39	                        });
40	
41	        // Defensive: use iteration counter instead of time-based safety timeout
42	        var iterations = 0;
43	        app.Iteration += IterationHandler;
44	
45	        try
46	        {
47	            app.Run<Runnable> ();
48	
49	            Assert.True (firstFired);
50	            Assert.True (secondFired);
51	        }
52	        finally
53	        {
54	            app.Iteration -= IterationHandler;
55	        }
56	
57	        return;
58	
59	        void IterationHandler (object? s, EventArgs<IApplication?> e)
60	        {
61	            iterations++;
62	
63	            // Stop if test objectives met or safety limit reached
64	            if ((firstFired && secondFired) || iterations > 1000)
65	            {
66	                app.RequestStop ();
67	            }
68	        }
69	    }
