                            () =>
                            {
                                Interlocked.Increment (ref firedCount);

                                return false;
                            });
        }

        var iterations = 0;

        app.Iteration += IterationHandler;

        try
        {
            app.Run<Runnable> ();

            Assert.Equal (TIMEOUT_COUNT, firedCount);
        }
        finally
        {
            app.Iteration -= IterationHandler;
        }

        return;

        void IterationHandler (object? s, EventArgs<IApplication?> e)
        {
