3	public partial class View
4	{
5	    // NOTE: NeedsDrawRect is not currently used to clip drawing to only the invalidated region.
6	    //       It is only used within SetNeedsDraw to propagate redraw requests to subviews.
7	    // NOTE: Consider changing NeedsDrawRect from Rectangle to Region for more precise invalidation
8	    //       NeedsDraw is already efficiently cached via NeedsDrawRect. It checks:
9	    //       1. NeedsDrawRect (cached by SetNeedsDraw/ClearNeedsDraw)
10	    //       2. Adornment NeedsDraw flags (each cached separately)
11	    /// <summary>
12	    ///     INTERNAL: Gets the viewport-relative region that needs to be redrawn.
13	    /// </summary>
14	    internal Rectangle NeedsDrawRect { get; private set; } = Rectangle.Empty;
15	
16	    /// <summary>Gets whether the view needs to be redrawn.</summary>
17	    /// <remarks>
18	    ///     <para>
19	    ///         Will be <see langword="true"/> if the <see cref="NeedsLayout"/> property is <see langword="true"/> or if
20	    ///         any part of the view's <see cref="Viewport"/> needs to be redrawn.
21	    ///     </para>
22	    /// </remarks>
23	    public bool NeedsDraw =>
24	        Visible && (NeedsDrawRect != Rectangle.Empty || Margin.View?.NeedsDraw == true || Border.View?.NeedsDraw == true || Padding.View?.NeedsDraw == true);
25	
26	    /// <summary>
27	    ///     Sets <see cref="NeedsDraw"/> to <see langword="true"/> indicating the <see cref="Viewport"/> of this View needs to
28	    ///     be redrawn.
29	    /// </summary>
30	    /// <remarks>
31	    ///     If the view is not visible (<see cref="Visible"/> is <see langword="false"/>), this method
32	    ///     does nothing.
33	    /// </remarks>
34	    public void SetNeedsDraw ()
35	    {
36	        Rectangle viewport = Viewport;
37	
38	        if (!Visible || (NeedsDrawRect != Rectangle.Empty && viewport.IsEmpty))
39	        {
40	            // This handles the case where the view has not been initialized yet
41	            return;
42	        }
43	
44	        SetNeedsDraw (viewport);
45	    }
46	
47	    /// <summary>Expands the area of this view needing to be redrawn to include <paramref name="viewPortRelativeRegion"/>.</summary>
48	    /// <remarks>
49	    ///     <para>
50	    ///         The location of <paramref name="viewPortRelativeRegion"/> is relative to the View's <see cref="Viewport"/>.
51	    ///     </para>
52	    ///     <para>
53	    ///         If the view has not been initialized (<see cref="IsInitialized"/> is <see langword="false"/>), the area to be
54	    ///         redrawn will be the <paramref name="viewPortRelativeRegion"/>.
55	    ///     </para>
56	    /// </remarks>
57	    /// <param name="viewPortRelativeRegion">The <see cref="Viewport"/>relative region that needs to be redrawn.</param>
58	    public void SetNeedsDraw (Rectangle viewPortRelativeRegion)
59	    {
60	        // Invalidate the cached drawn region used for TransparentMouse hit-testing.
61	        // It will be repopulated on the next Draw() pass.
62	        CachedDrawnRegion = null;
63	
64	        // If we are at the top of the hierarchy, we're a runnable,
65	        // and we need to ensure any other Runnables get redrawn.
66	        if (App?.TopRunnableView == this && App is { })
67	        {
68	            //App?.ClearScreenNextIteration = true;
69	            List<View?> runnables = [.. App?.SessionStack?.Select (r => r.Runnable as View).Where (v => v != this && v?.NeedsDraw == false)!];
70	
71	            foreach (View? runnable in runnables)
72	            {
73	                runnable?.SetNeedsDraw ();
74	            }
75	        }
76	
77	        if (!Visible)
78	        {
79	            return;
80	        }
81	
82	        if (NeedsDrawRect.IsEmpty)
83	        {
84	            NeedsDrawRect = viewPortRelativeRegion;
85	        }
86	        else
87	        {
88	            int x = Math.Min (Viewport.X, viewPortRelativeRegion.X);
89	            int y = Math.Min (Viewport.Y, viewPortRelativeRegion.Y);
90	            int w = Math.Max (Viewport.Width, viewPortRelativeRegion.Width);
91	            int h = Math.Max (Viewport.Height, viewPortRelativeRegion.Height);
92	            NeedsDrawRect = new Rectangle (x, y, w, h);
93	        }
94	
95	        // Do not set on Margin - it will be drawn in a separate pass.
96	
97	        if (Border.Thickness != Thickness.Empty)
98	        {
99	            Border.View?.SetNeedsDraw ();
100	        }
101	
102	        if (Padding.Thickness != Thickness.Empty)
103	        {
104	            Padding.View?.SetNeedsDraw ();
105	        }
106	
107	        SuperView?.SetSubViewNeedsDrawDownHierarchy ();
108	
109	        if (this is AdornmentView adornment)
110	        {
111	            adornment.Adornment?.Parent?.SetSubViewNeedsDrawDownHierarchy ();
112	        }
113	
114	        foreach (View subview in InternalSubViews.Snapshot ())
115	        {
116	            if (!subview.Frame.IntersectsWith (viewPortRelativeRegion))
117	            {
118	                continue;
119	            }
120	            Rectangle subviewRegion = Rectangle.Intersect (subview.Frame, viewPortRelativeRegion);
121	            subviewRegion.X -= subview.Frame.X;
122	            subviewRegion.Y -= subview.Frame.Y;
123	            subview.SetNeedsDraw (subviewRegion);
124	        }
125	    }
126	
127	    /// <summary>INTERNAL: Clears <see cref="NeedsDraw"/> and <see cref="SubViewNeedsDraw"/> for this view and all SubViews.</summary>
128	    /// <remarks>
129	    ///     See <see cref="SubViewNeedsDraw"/> is a cached value that is set when any subview or adornment requests a redraw.
130	    ///     It may not always be in sync with the actual state of the subviews.
131	    /// </remarks>
132	    internal void ClearNeedsDraw ()
133	    {
134	        NeedsDrawRect = Rectangle.Empty;
135	
136	        Margin.View?.ClearNeedsDraw ();
137	        Border.View?.ClearNeedsDraw ();
138	        Padding.View?.ClearNeedsDraw ();
139	
140	        foreach (View subview in InternalSubViews.Snapshot ())
141	        {
142	            subview.ClearNeedsDraw ();
143	        }
144	
145	        SubViewNeedsDraw = false;
146	
147	        // This ensures LineCanvas' get redrawn
148	        if (!SuperViewRendersLineCanvas)
149	        {
150	            LineCanvas.Clear ();
151	        }
152	    }
153	
154	    // NOTE: SubViewNeedsDraw is decoupled from the actual state of the subviews (and adornments).
155	    //       It is a performance optimization to avoid having to traverse all subviews and adornments to check if any need redraw.
156	    //       As a result the code is fragile and can get out of sync; care must be taken to ensure it is set and cleared correctly.
157	    /// <summary>
158	    ///     INTERNAL: Gets whether any SubViews need to be redrawn.
159	    /// </summary>
160	    /// <remarks>
161	    ///     See <see cref="SubViewNeedsDraw"/> is a cached value that is set when any subview or adornment requests a redraw.
162	    ///     It may not always be in sync with the actual state of the subviews.
163	    /// </remarks>
164	    internal bool SubViewNeedsDraw { get; private set; }
165	
166	    /// <summary>INTERNAL: Sets <see cref="SubViewNeedsDraw"/> to <see langword="true"/> for this View and all Superviews.</summary>
167	    /// <remarks>
168	    ///     See <see cref="SubViewNeedsDraw"/> is a cached value that is set when any subview or adornment requests a redraw.
169	    ///     It may not always be in sync with the actual state of the subviews.
170	    /// </remarks>
171	    internal void SetSubViewNeedsDrawDownHierarchy ()
172	    {
173	        if (!Visible)
174	        {
175	            return;
176	        }
177	
178	        SubViewNeedsDraw = true;
179	
180	        if (this is AdornmentView adornment)
181	        {
182	            adornment.Adornment?.Parent?.SetSubViewNeedsDrawDownHierarchy ();
183	        }
184	
185	        if (SuperView is { SubViewNeedsDraw: false })
186	        {
187	            SuperView.SetSubViewNeedsDrawDownHierarchy ();
188	        }
189	    }
