[Fact]
public void AutoSpin_SetBeforeAddingToInitializedView_AdvancesFrame ()
{
    // Claude - Opus 4.5
    using IApplication app = Application.Create ();
    app.Init (DriverRegistry.Names.ANSI);

    using Window main = new () { Width = 5, Height = 1 };

    SpinnerView spinner = new ()
    {
        X = 0,
        Y = 0,
        SpinDelay = 1,
        AutoSpin = true
    };

    main.Add (spinner);

    var advances = 0;
    app.Iteration += appIteration;

    try
    {
        app.Run (main);

        Assert.True (advances > 0);
    }
    finally
    {
        app.Iteration -= appIteration;
    }

    return;

    void appIteration (object? sender, EventArgs<IApplication?> e)
    {
        Thread.Sleep (2);

        if (!spinner.NeedsDraw)
        {
            return;
        }

        advances++;

        if (advances > 0)
        {
            app.RequestStop ();
        }
    }
}

